import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"基础武学-剑法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础武学-剑法.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础武学-剑法.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/武学基础/基础武学-剑法.md"};function p(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"基础武学-剑法",tabindex:"-1"},[s("基础武学-剑法 "),e("a",{class:"header-anchor",href:"#基础武学-剑法","aria-label":'Permalink to "基础武学-剑法"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001")])])],-1),o('<h1 id="基础武学-剑法-1" tabindex="-1">基础武学-剑法 <a class="header-anchor" href="#基础武学-剑法-1" aria-label="Permalink to &quot;基础武学-剑法&quot;">​</a></h1><p>基础武学-剑法<br> 江湖中最最基础的武功招法，在结合不同的基本功和兵器招式之后，大囧朝廷通过总结推演出新，创新性的为百姓和天下所有武学新人创造了这些更接近于实战的基础武功，并划分江南漠北地区二十八县推广推陈，力求普及，为未来扫平江湖提前埋下另一道伏笔。</p><p>本系列下所有能力皆需要内力能量池才可购买。</p><p>基础剑法 D+1000<br> 法以钩、挂、点、挑、剌、撩、劈、为主，练习时要求剑随身走，以 身带剑， 应用时要做到剑与身合，身与气合，气与神合。神形之中要做到形与意合，意与气合。六合之中亦需要手、眼、身、法、步神形俱妙，随之剑身轻烈身形始得之乃人持剑非剑痴人尔。</p><p>使用一个标准动作花费1内力进行攻击，你的这一次剑法攻击在精气神意的统合之下收束于剑意之中以内力维持剑招锋锐斩出，你获得一种特殊的攻击方式，将你的剑意从剑刃之中挥洒而出，剑气挥洒之间具有6米的攻击射程，并可以同时攻击两个对象，使用反射豁免进行对抗。</p><p>这是一个攻击技。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
